### Example HK Configuration (`hk.pkl`)

Source: https://github.com/jdx/hk/blob/main/docs/getting_started.md

An example of an 'hk.pkl' file demonstrating how to define local linters (eslint, prettier) and hooks (pre-commit). It includes configurations for file globbing, check commands, and hook behavior like 'fix' and 'stash'.

```pkl
amends "package://github.com/jdx/hk/releases/download/v1.27.0/hk@1.27.0#/Config.pkl"
import "package://github.com/jdx/hk/releases/download/v1.27.0/hk@1.27.0#/Builtins.pkl"

local linters = new Mapping<String, Step> {
    // linters can be manually defined
    ["eslint"] {
        // the files to run the linter on, if no files are matched, the linter will be skipped
        glob = List("*.js"; "*.ts")
        // a command that returns non-zero to fail the check
        check = "eslint {{files}}"
    }
    // linters can also be specified with the builtins pkl library
    ["prettier"] = Builtins.prettier
    // with pkl, builtins can also be extended:
    ["prettier-yaml"] = (Builtins.prettier) {
        glob = List("*.yaml"; "*.yml")
    }
}

hooks {
    ["pre-commit"] {
        fix = true    // runs the "fix" step of linters to modify files
        stash = "git" // stashes unstaged changes when running fix steps
        steps {
            ["prelint"] {
                check = "mise run prelint"
                exclusive = true // blocks other steps from starting until this one finishes
            }
            ...linters
            ["postlint"] {
                check = "mise run postlint"
                exclusive = true
            }
        }
    }
}
```

--------------------------------

### HK PKL - Basic Configuration Structure

Source: https://context7.com/jdx/hk/llms.txt

Demonstrates the basic structure of an `hk.pkl` configuration file, showcasing global settings, environment variables, exclusions, linters, and hook definitions. This example covers common features like importing other configurations and defining reusable linter steps.

```pkl
amends "package://github.com/jdx/hk/releases/download/v1.27.0/hk@1.27.0#/Config.pkl"
import "package://github.com/jdx/hk/releases/download/v1.27.0/hk@1.27.0#/Builtins.pkl"
import "package://github.com/jdx/hk/releases/download/v1.27.0/hk@1.27.0#/Types.pkl"

// Global environment variables
env {
    ["NODE_ENV"] = "production"
    ["HK_FAIL_FAST"] = "0"
}

// Global file exclusions
exclude = List("node_modules", "dist", "build", "**/*.min.js")

// Or use regex for complex patterns
exclude = Types.Regex(#".*\.(test|spec)\.(js|ts)$"#)

// Preferred default branch
default_branch = "main"

// Abort on first failure
fail_fast = true

// Control which skip reasons are displayed
display_skip_reasons = List("profile-not-enabled", "no-files-to-process")

// Enable specific warning categories
warnings = List("missing-profiles")

// Define reusable linter configurations
local linters = new Mapping<String, Step> {
    ["prettier"] = (Builtins.prettier) {
        batch = true
        glob = List("*.js", "*.ts", "*.json", "*.md")
    }

    ["eslint"] {
        glob = List("*.js", "*.jsx", "*.ts", "*.tsx")
        check = "eslint {{files}}"
        fix = "eslint --fix {{files}}"
        batch = true
        check_first = true
        env {
            ["NODE_ENV"] = "development"
        }
    }

    ["cargo-clippy"] = (Builtins.cargo_clippy) {
        profiles = List("slow")
        check = "cargo clippy --manifest-path {{workspace_indicator}} -- -D warnings"
    }

    ["custom-validator"] {
        glob = "**/*.yaml"
        check = "yamllint {{files}}"
        profiles = List("strict")
        condition = "test -f .yamllint"
    }
}

// Define hooks with steps and options
hooks {
    ["pre-commit"] {
        fix = true
        stash = "git"
        steps {
            ["prelint"] {
                check = "mise run prelint"
                exclusive = true
            }
            ...linters
            ["postlint"] {
                check = "echo 'Linting complete'"
                exclusive = true
            }
        }
        report = #"node scripts/upload-timings.js <<<"$HK_REPORT_JSON""#
    }

    ["pre-push"] {
        fix = false
        steps = linters
    }

    ["commit-msg"] {
        steps {
            ["validate-commit"] {
                check = "grep -q '^(fix|feat|chore):' {{commit_msg_file}}"
            }
        }
    }

    ["prepare-commit-msg"] {
        steps {
            ["template"] {
                check = "echo '# Enter commit message' > {{commit_msg_file}}"
            }
        }
    }

    ["check"] {
        steps = linters
    }

    ["fix"] {
        fix = true
        steps = linters
    }
}

```

--------------------------------

### Define Step Configuration with Glob Patterns and Dependencies in Pkl

Source: https://github.com/jdx/hk/blob/main/docs/glossary.md

Shows a detailed step configuration in Pkl, including glob patterns for file selection ('glob', 'stage'), commands for checking and fixing code ('check', 'fix'), and a dependency on another step ('depends').

```pkl
steps {
  ["eslint"] {
    glob = List("*.js", "*.ts")
    stage = List("*.js", "*.ts")
    check = "eslint {{files}}"
    fix = "eslint --fix {{files}}"
    depends = List("prettier")  // Run after prettier
  }
}
```

--------------------------------

### Example Global hkrc Configuration

Source: https://github.com/jdx/hk/blob/main/docs/configuration.md

This PKL code demonstrates a global hkrc file. It imports built-in configurations, defines local linters like prettier and eslint with glob patterns and check/fix commands, and sets up a pre-commit hook that utilizes these linters. This allows for consistent linting rules across all projects managed by hk.

```pkl
amends "package://github.com/jdx/hk/releases/download/v1.27.0/hk@1.27.0#/Config.pkl"
import "package://github.com/jdx/hk/releases/download/v1.27.0/hk@1.27.0#/Builtins.pkl"

local linters {
    ["prettier"] = Builtins.prettier
    ["eslint"] {
        glob = List("*.js", "*.ts")
        check = "eslint {{files}}"
        fix = "eslint --fix {{files}}"
    }
}

hooks {
    ["pre-commit"] {
        fix = true
        steps = linters
    }
}
```

--------------------------------

### Basic HK Configuration with pkl-lang

Source: https://github.com/jdx/hk/blob/main/docs/configuration.md

Demonstrates a fundamental `hk.pkl` file for setting up linters and Git hooks. It imports base configurations, defines custom linters like ESLint and Prettier, and configures `pre-commit` and `pre-push` hooks.

```pkl
amends "package://github.com/jdx/hk/releases/download/v1.27.0/hk@1.27.0#/Config.pkl"
import "package://github.com/jdx/hk/releases/download/v1.27.0/hk@1.27.0#/Builtins.pkl"

local linters = new Mapping<String, Step> {
    // linters can be manually defined
    ["eslint"] {
        // the files to run the linter on, if no files are matched, the linter will be skipped
        // this will filter the staged files and return the subset matching these globs
        glob = List("*.js", "*.ts")
        // these files will be staged after the fix step modifies them
        stage = List("*.js", "*.ts")
        // the command to run that makes no changes
        check = "eslint {{files}}"
        // the command to run that fixes the files (used by default)
        fix = "eslint --fix {{files}}"
    }
    // linters can also be specified with the Builtins pkl library
    ["prettier"] = Builtins.prettier
}

hooks {
    ["pre-commit"] {
        fix = true       // runs the fix step to make modifications
        stash = "git"    // stashes unstaged changes before running fix steps
        steps = linters
    }
    ["pre-push"] {
        steps = linters
    }
    // "fix" and "check" are special steps for `hk fix` and `hk check` commands
    ["fix"] {
        fix = true
        steps = linters
    }
    ["check"] {
        steps = linters
        // optional: run a report after the hook finishes; HK_REPORT_JSON contains timing JSON
        report = #"node scripts/upload-timings.js <<<\"$HK_REPORT_JSON\""#
    }
}

```

