import "package://github.com/jdx/hk/releases/download/v1.27.0/hk@1.27.0#/Types.pkl"

// Global environment variables
env {
    ["NODE_ENV"] = "production"
    ["HK_FAIL_FAST"] = "0"
}

// Global file exclusions
exclude = List("node_modules", "dist", "build", "**/*.min.js")

// Or use regex for complex patterns
exclude = Types.Regex(#".*\.(test|spec)\.(js|ts)$"#)

// Preferred default branch
default_branch = "main"

// Abort on first failure
fail_fast = true

// Control which skip reasons are displayed
display_skip_reasons = List("profile-not-enabled", "no-files-to-process")

// Enable specific warning categories
warnings = List("missing-profiles")

// Define reusable linter configurations
local linters = new Mapping<String, Step> {
    ["prettier"] = (Builtins.prettier) {
        batch = true
        glob = List("*.js", "*.ts", "*.json", "*.md")
    }

    ["eslint"] {
        glob = List("*.js", "*.jsx", "*.ts", "*.tsx")
        check = "eslint {{files}}"
        fix = "eslint --fix {{files}}"
        batch = true
        check_first = true
        env {
            ["NODE_ENV"] = "development"
        }
    }

    ["cargo-clippy"] = (Builtins.cargo_clippy) {
        profiles = List("slow")
        check = "cargo clippy --manifest-path {{workspace_indicator}} -- -D warnings"
    }

    ["custom-validator"] {
        glob = "**/*.yaml"
        check = "yamllint {{files}}"
        profiles = List("strict")
        condition = "test -f .yamllint"
    }
}

// Define hooks with steps and options
hooks {
    ["pre-commit"] {
        fix = true
        stash = "git"
        steps {
            ["prelint"] {
                check = "mise run prelint"
                exclusive = true
            }
            ...linters
            ["postlint"] {
                check = "echo 'Linting complete'"
                exclusive = true
            }
        }
        report = #"node scripts/upload-timings.js <<<"$HK_REPORT_JSON""#
    }

    ["pre-push"] {
        fix = false
        steps = linters
    }

    ["commit-msg"] {
        steps {
            ["validate-commit"] {
                check = "grep -q '^(fix|feat|chore):' {{commit_msg_file}}"
            }
        }
    }

    ["prepare-commit-msg"] {
        steps {
            ["template"] {
                check = "echo '# Enter commit message' > {{commit_msg_file}}"
            }
        }
    }

    ["check"] {
        steps = linters
    }

    ["fix"] {
        fix = true
        steps = linters
    }
}

```

